+
+export class ClaudeAcpSessionCreateTimeoutError extends AcpxOperationalError {
+  constructor(message: string, options?: AcpxErrorOptions) {
+    super(message, {
+      outputCode: "TIMEOUT",
+      detailCode: "CLAUDE_ACP_SESSION_CREATE_TIMEOUT",
